const ACTIVE_PUBLISH_LOCK_TTL_MS = 45 * 60 * 1000;
const ACTIVE_PAD_OPERATION_TTL_MS = 90 * 60 * 1000;
const activePublishCommands = new Map<string, {
  chatId: number;
  key: string;
  label: string;
  startedAt: number;
}>();
const activePadOperations = new Map<string, {
  key: string;
  label: string;
  chatId: number;
  startedAt: number;
}>();
const cancelledPadOperationKeys = new Set<string>();

class TelegramTaskCancelledError extends Error {
  constructor(message = "当前任务已被用户强制中止") {
    super(message);
    this.name = "TelegramTaskCancelledError";
  }
}

function isTelegramTaskCancelledError(error: unknown) {
  return error instanceof TelegramTaskCancelledError
    || /当前任务已被用户强制中止|用户强制中止/.test(rawErrorMessage(error));
}

function purgeExpiredPublishCommands() {
  const now = Date.now();
  for (const [scope, active] of activePublishCommands.entries()) {
    if (now - active.startedAt >= ACTIVE_PUBLISH_LOCK_TTL_MS) {
      activePublishCommands.delete(scope);
    }
  }
}

function purgeExpiredPadOperations() {
  const now = Date.now();
  for (const [padCode, active] of activePadOperations.entries()) {
    if (now - active.startedAt >= ACTIVE_PAD_OPERATION_TTL_MS) {
      activePadOperations.delete(padCode);
    }
  }
}

function publishCommandScope(chatId: number, scopeKey: string) {
  return `${chatId}:${scopeKey}`;
}

function acquirePublishCommand(chatId: number, key: string, label: string, scopeKey = key) {
  purgeExpiredPublishCommands();
  const now = Date.now();
  const active = activePublishCommands.get(publishCommandScope(chatId, scopeKey));
  if (active && now - active.startedAt < ACTIVE_PUBLISH_LOCK_TTL_MS) return false;
  activePublishCommands.set(publishCommandScope(chatId, scopeKey), { chatId, key, label, startedAt: now });
  return true;
}

function releasePublishCommand(chatId: number, key: string, scopeKey = key) {
  const scope = publishCommandScope(chatId, scopeKey);
  const active = activePublishCommands.get(scope);
  if (active?.key === key) activePublishCommands.delete(scope);
}

function acquirePadOperation(chatId: number, padCode: string, key: string, label: string) {
  purgeExpiredPadOperations();
  cancelledPadOperationKeys.delete(key);
  const active = activePadOperations.get(padCode);
  if (active && active.key !== key) return active;
  activePadOperations.set(padCode, { key, label, chatId, startedAt: Date.now() });
  return null;
}

function releasePadOperation(padCode: string, key: string) {
  const active = activePadOperations.get(padCode);
  if (active?.key === key) activePadOperations.delete(padCode);
  cancelledPadOperationKeys.delete(key);
}

function listActiveRuntimeOperationsForChat(chatId: number) {
  purgeExpiredPublishCommands();
  purgeExpiredPadOperations();
  const padOperations = Array.from(activePadOperations.entries())
    .filter(([, active]) => active.chatId === chatId)
    .map(([padCode, active]) => ({
      type: "pad" as const,
      scope: padCode,
      padCode,
      label: active.label,
      startedAt: active.startedAt,
    }));
  const padKeys = new Set(padOperations.map((item) => item.padCode));
  const publishOperations = Array.from(activePublishCommands.entries())
    .filter(([, active]) => active.chatId === chatId)
    .map(([scope, active]) => ({
      type: "publish" as const,
      scope,
      padCode: scope.startsWith(`${chatId}:pad:`) ? scope.slice(`${chatId}:pad:`.length) : undefined,
      label: active.label,
      startedAt: active.startedAt,
    }))
    .filter((item) => !item.padCode || !padKeys.has(item.padCode));
  return [...padOperations, ...publishOperations].sort((a, b) => a.startedAt - b.startedAt);
}

function assertPadOperationNotCancelled(key: string) {
  if (cancelledPadOperationKeys.has(key)) {
    throw new TelegramTaskCancelledError();
  }
}

async function sendDuplicatePublishNotice(bot: TelegramBot, chatId: number, scopeKey?: string) {
  const active = scopeKey
    ? activePublishCommands.get(publishCommandScope(chatId, scopeKey))
    : Array.from(activePublishCommands.values()).find((item) => item.chatId === chatId);
  const label = active?.label || "发布";
  await bot.sendMessage(chatId, `⚠️ 请勿重复发送指令\n\n上一条${label}指令正在执行中，请等待它完成。第二次指令已忽略，不会影响上一条任务。`).catch(() => undefined);
}

async function sendPadBusyNotice(bot: TelegramBot, chatId: number, padCode: string, active: { label: string; chatId: number; startedAt: number }) {
  const minutes = Math.max(1, Math.ceil((Date.now() - active.startedAt) / 60_000));
  await bot.sendMessage(
    chatId,
    `⚠️ 设备正在執行任務\n\n设备：${padCode}\n目前任務：${active.label}\n已執行：約 ${minutes} 分鐘\n\n同一台设备不能同時發布/養號/登入，請等目前任務結束後再試。`,
  ).catch(() => undefined);
}

async function resumePendingThreadsProfileAction(bot: TelegramBot, chatId: number, archiveId: string): Promise<boolean> {
  const resume = pendingThreadsProfileResumeActions.get(chatId);
  if (!resume || resume.archiveId !== archiveId) return false;
  pendingThreadsProfileResumeActions.delete(chatId);

  const opTitle = resume.stage === "await_name"
    ? "Threads 名稱"
    : resume.stage === "await_bio"
      ? "Threads 簡介"
      : "Threads 簡介連結";
  const action = resume.stage === "await_name"
    ? "名稱修改"
    : resume.stage === "await_bio"
      ? "簡介修改"
      : "簡介新增連結";
  const valueLabel = resume.stage === "await_name"
    ? "名稱"
    : resume.stage === "await_bio"
      ? "簡介"
      : "連結";
  const progressTitle = resume.stage === "await_name"
    ? "🏷 正在修改 Threads 名稱"
    : resume.stage === "await_bio"
      ? "📝 正在修改 Threads 簡介"
      : "🔗 正在更新 Threads 簡介連結";
  const opKey = `threads-profile-resume-${resume.stage}-${chatId}-${Date.now()}`;
  const active = acquirePadOperation(chatId, resume.padCode, opKey, opTitle);
  if (active) {
    await sendPadBusyNotice(bot, chatId, resume.padCode, active);
    return true;
  }

  const statusMsg = await bot.sendMessage(chatId, [
    progressTitle,
    "",
    `设备：${resume.padName || resume.padCode}`,
    `${valueLabel}：${resume.input}`,
    "",
    "✅ Threads 登入流程已完成，正在繼續執行剛才的資料修改...",
  ].join("\n"), {
    reply_markup: { inline_keyboard: [[{ text: "◀️ 返回 Threads 帳號", callback_data: resume.returnCallback }]] },
  });
  const stopTyping = startTelegramTyping(bot, chatId);
  const progress = (p: PublishProgress) => {
    bot.editMessageText([
      progressTitle,
      "",
      `设备：${resume.padName || resume.padCode}`,
      `${valueLabel}：${resume.input}`,
      "",
      `${p.done ? "✅" : "⏳"} ${p.step}`,
    ].join("\n"), {
      chat_id: chatId,
      message_id: statusMsg.message_id,
      reply_markup: { inline_keyboard: [[{ text: "◀️ 返回 Threads 帳號", callback_data: resume.returnCallback }]] },
    }).catch(() => undefined);
  };

  try {
    const creds = resolveMobileCredentials();
    const result = resume.stage === "await_name"
      ? await updateThreadsProfileName(creds, resume.padCode, resume.input, progress)
      : resume.stage === "await_bio"
        ? await updateThreadsProfileBio(creds, resume.padCode, resume.input, progress)
        : await updateThreadsProfileLink(creds, resume.padCode, resume.input, progress);
    stopTyping();
    await bot.sendMessage(chatId, [
      result.state === "verified" ? `✅ Threads ${valueLabel}已更新` : `⚠️ Threads ${valueLabel}已提交`,
      "",
      `设备：${resume.padName || resume.padCode}`,
      `${valueLabel}：${resume.input}`,
      result.detail,
    ].join("\n"), {
      reply_markup: { inline_keyboard: [[{ text: "◀️ 返回 Threads 帳號", callback_data: resume.returnCallback }]] },
    });
    if (result.screenshotUrl) {
      await sendOriginalScreenshotDocument(bot, chatId, result.screenshotUrl, `📸 Threads ${valueLabel}修改後截圖`).catch(() => undefined);
    }
    return true;
  } catch (error) {
    stopTyping();
    const notice = formatCloudAccountStateNotice(rawErrorMessage(error), {
      action,
      padName: resume.padName,
      padCode: resume.padCode,
    });
    await bot.editMessageText(notice?.kind === "login_required"
      ? [
          "⚠️ Threads 仍未登入，資料修改已停止",
          "",
          `设备：${resume.padName || resume.padCode}`,
          `${valueLabel}：${resume.input}`,
          "",
          "請完成登入後再次點擊修改動作。",
        ].join("\n")
      : [
          `❌ Threads ${valueLabel}修改失敗`,
          "",
          `设备：${resume.padName || resume.padCode}`,
          `原因：${formatUserFacingError(error, "請稍後重試。")}`,
        ].join("\n"), {
      chat_id: chatId,
      message_id: statusMsg.message_id,
      reply_markup: { inline_keyboard: [[{ text: "◀️ 返回 Threads 帳號", callback_data: resume.returnCallback }]] },
    }).catch(() => undefined);
    return true;
  } finally {
    releasePadOperation(resume.padCode, opKey);
  }
}

function resolvePendingPostSelection(chatId: number, data: string, prefix: string) {
  const index = Number(data.slice(prefix.length));
  const selection = pendingPostSelections.get(chatId);
  if (!selection || !Number.isFinite(index) || index < 0) return null;
  const postId = selection.postIds[index];
  if (!postId) return null;
  return { archiveId: selection.archiveId, postId, index, displayIndex: index + 1, source: selection.source, groupContentType: selection.groupContentType };
}

const STORED_POSTS_PAGE_SIZE = 5;

type PersonaContentTypeTarget = "posts" | "history" | "publish";

export function buildPersonaContentTypeCallback(
  target: PersonaContentTypeTarget,
  archiveId: string,
  groupContentType: TelegramGroupContentType,
) {
  const prefix = target === "publish" ? "pub" : target;
  return `${prefix}_${archiveId}_ct_${groupContentType}`;
}

export function parsePersonaContentTypeCallback(data: string): {
  target: PersonaContentTypeTarget;
  archiveId: string;
  groupContentType: TelegramGroupContentType;
} | null {
  const match = data.match(/^(posts|history|pub)_(.+)_ct_(free|paid)$/);
  if (!match) return null;
  return {
    target: match[1] === "pub" ? "publish" : match[1] as PersonaContentTypeTarget,
    archiveId: match[2],
    groupContentType: match[3] as TelegramGroupContentType,
  };
}

export function buildPersonaContentTypePickerRows(args: {
  archiveId: string;
  target: PersonaContentTypeTarget;
  counts?: Partial<Record<TelegramGroupContentType, number>>;
}) {
  const freeCount = Number(args.counts?.free || 0);
  const paidCount = Number(args.counts?.paid || 0);
  const rows = [
    [
      { text: `免費內容（${freeCount}）`, callback_data: buildPersonaContentTypeCallback(args.target, args.archiveId, "free") },
      { text: `付費內容（${paidCount}）`, callback_data: buildPersonaContentTypeCallback(args.target, args.archiveId, "paid") },
    ],
  ];
  rows.push([{ text: "◀️ 返回人設詳情", callback_data: `pd_${args.archiveId}` }]);
  return rows;
}

function buildStoredPostsPageCallback(archiveId: string, page: number, groupContentType?: TelegramGroupContentType) {
  const suffix = groupContentType ? `_ct_${groupContentType}` : "";
  return `posts_${archiveId}${suffix}_p${Math.max(0, page)}`;
}

function buildFavoritePostsPageCallback(archiveId: string, page = 0) {
  return `favs_${archiveId}_p${Math.max(0, page)}`;
}

function buildPostSourcePageCallback(
  archiveId: string,
  source?: "posts" | "favorites",
  page = 0,
  groupContentType?: TelegramGroupContentType,
) {
  return source === "favorites"
    ? buildFavoritePostsPageCallback(archiveId, page)
    : buildStoredPostsPageCallback(archiveId, page, groupContentType);
}

const PERSONA_LIST_PAGE_SIZE = 8;

export function buildSimplePagedCallback(root: string, page: number) {
  const safePage = Math.max(0, Math.floor(page || 0));
  return safePage > 0 ? `${root}_p${safePage}` : root;
}

export function parseSimplePagedCallback(data: string, root: string): number | null {
  if (data === root) return 0;
  const prefix = `${root}_p`;
  if (!data.startsWith(prefix)) return null;
  const page = Number(data.slice(prefix.length));
  if (!Number.isFinite(page) || page < 0) return null;
  return Math.floor(page);
}

function paginateListItems<T>(items: T[], page: number, pageSize = PERSONA_LIST_PAGE_SIZE) {
  const totalPages = Math.max(1, Math.ceil(items.length / pageSize));
  const safePage = Math.min(Math.max(0, Math.floor(page || 0)), totalPages - 1);
  const start = safePage * pageSize;
  return {
    page: safePage,
    totalPages,
    totalItems: items.length,
    items: items.slice(start, start + pageSize),
  };
}

export function buildListPaginationRows(args: {
  page: number;
  totalPages: number;
  callbackForPage: (page: number) => string;
}) {
  const totalPages = Math.max(1, Math.floor(args.totalPages || 1));
  const safePage = Math.min(Math.max(0, Math.floor(args.page || 0)), totalPages - 1);
  if (totalPages <= 1) return [];
  const rows: Array<Array<{ text: string; callback_data: string }>> = [];
  if (safePage > 0) {
    rows.push([
      { text: "⏮ 首頁", callback_data: args.callbackForPage(0) },
      { text: "◀️ 上一頁", callback_data: args.callbackForPage(safePage - 1) },
    ]);
  }
  rows.push([{ text: `${safePage + 1}/${totalPages}`, callback_data: args.callbackForPage(safePage) }]);
  if (safePage < totalPages - 1) {
    rows.push([
      { text: "下一頁 ▶️", callback_data: args.callbackForPage(safePage + 1) },
      { text: "尾頁 ⏭", callback_data: args.callbackForPage(totalPages - 1) },
    ]);
  }
  return rows;
}

function buildPagedPersonaSelectorPayload(args: {
  title: string;
  list: PersonaListSummary[];
  page?: number;
  itemCallback: (persona: PersonaListSummary) => string;
  pageCallbackRoot: string;
  topRows?: Array<Array<{ text: string; callback_data: string }>>;
  footerRows?: Array<Array<{ text: string; callback_data: string }>>;
  emptyText: string;
  emptyRows?: Array<Array<{ text: string; callback_data: string }>>;
  buttonText?: (persona: PersonaListSummary) => string;
  parseMode?: "Markdown";
  summaryLines?: (visible: PersonaListSummary[], pageInfo: { page: number; totalPages: number; totalItems: number }) => string[];
}): TelegramMenuPayload {
  const pageInfo = paginateListItems(args.list, args.page || 0, PERSONA_LIST_PAGE_SIZE);
  if (args.list.length === 0) {
    return {
      text: args.emptyText,
      options: {
        ...(args.parseMode ? { parse_mode: args.parseMode } : {}),
        ...(args.emptyRows?.length ? { reply_markup: { inline_keyboard: args.emptyRows } } : {}),
      },
    };
  }
  const titleLines = [args.title];
  if (pageInfo.totalPages > 1) {
    titleLines.push("", `第 ${pageInfo.page + 1}/${pageInfo.totalPages} 頁`);
  }
  const summaries = args.summaryLines?.(pageInfo.items, pageInfo) || [];
  if (summaries.length) {
    titleLines.push("", ...summaries);
  }
  const keyboard = [
    ...(args.topRows || []),
    ...pageInfo.items.map((persona) => ([{
      text: args.buttonText ? args.buttonText(persona) : formatPersonaButtonText(persona),
      callback_data: args.itemCallback(persona),
    }])),
    ...buildListPaginationRows({
      page: pageInfo.page,
      totalPages: pageInfo.totalPages,
      callbackForPage: (page) => buildSimplePagedCallback(args.pageCallbackRoot, page),
    }),
    ...(args.footerRows || []),
  ];
  return {
    text: titleLines.join("\n"),
    options: {
      ...(args.parseMode ? { parse_mode: args.parseMode } : {}),
      reply_markup: { inline_keyboard: keyboard },
    },
  };
}

function buildMatrixPersonaSelectionPayload(list: PersonaListSummary[], state: PendingMatrixPublish): TelegramMenuPayload {
  const pageInfo = paginateListItems(list, state.page || 0, PERSONA_LIST_PAGE_SIZE);
  const selected = new Set(state.archiveIds);
  const lines = [
    "🚀 *矩陣發布*",
    "",
    `已選人設：${selected.size} 個`,
    "請選擇要一起發布的人設。",
  ];
  if (pageInfo.totalPages > 1) lines.splice(2, 0, `第 ${pageInfo.page + 1}/${pageInfo.totalPages} 頁`);
  const start = pageInfo.page * PERSONA_LIST_PAGE_SIZE;
  const keyboard = [
    ...pageInfo.items.map((persona, index) => ([{
      text: `${selected.has(persona.id) ? "✅" : "⬜"} ${formatPersonaButtonText(persona)}`,
      callback_data: `mxpt_${persona.id}`,
    }])),
    ...buildListPaginationRows({
      page: pageInfo.page,
      totalPages: pageInfo.totalPages,
      callbackForPage: (page) => `mxpg_${page}`,
    }),
    [
      { text: "✅ 選本頁", callback_data: "mxpsel" },
      { text: "🧹 清本頁", callback_data: "mxpclr" },
    ],
    [{ text: `下一步：選擇來源（${selected.size}）`, callback_data: "mxpc" }],
    [{ text: "◀️ 返回人設列表", callback_data: "list_personas" }],
  ];
  return {
    text: lines.join("\n"),
    options: {
      parse_mode: "Markdown",
      reply_markup: { inline_keyboard: keyboard },
    },
  };
}

function buildMatrixSourceRows(): Array<Array<{ text: string; callback_data: string }>> {
  return [
    [{ text: "📝 待發布推文", callback_data: "mxsrc_posts" }],
    [{ text: "⭐ 收藏推文", callback_data: "mxsrc_favorites" }],
    [{ text: "◀️ 返回選人設", callback_data: "matrix_start" }],
  ];
}

function buildMatrixCountRowsForLimit(commonLimit: number, totalAvailable = 0): Array<Array<{ text: string; callback_data: string }>> {
  const rows: Array<Array<{ text: string; callback_data: string }>> = [];
  if (commonLimit > 0) {
    rows.push([{ text: `每人 ${commonLimit} 篇`, callback_data: `mxc_${commonLimit}` }]);
  }
  if (totalAvailable > 0) {
    rows.push([{ text: "每人全部", callback_data: "mxc_all" }]);
  }
  rows.push([{ text: "◀️ 返回平台", callback_data: "mxback_platform" }]);
  return rows;
}

function formatMatrixSourceLabel(source?: "posts" | "favorites") {
  return source === "favorites" ? "收藏推文" : "待發布推文";
}

function formatMatrixCountLabel(count?: number | "all") {
  return count === "all" ? "全部" : `每人 ${count || 1} 篇`;
}

function buildPersonaHistoryCallback(archiveId: string, groupContentType?: TelegramGroupContentType, page = 0) {
  const suffix = groupContentType ? `_ct_${groupContentType}` : "";
  const pageSuffix = page > 0 ? `_p${Math.max(0, page)}` : "";
  return `history_${archiveId}${suffix}${pageSuffix}`;
}

function buildPersonaPublishCallback(archiveId: string, groupContentType?: TelegramGroupContentType) {
  const suffix = groupContentType ? `_ct_${groupContentType}` : "";
  return `pub_${archiveId}${suffix}`;
}

function parsePersonaScopedCallback(data: string, prefix: "history_" | "pub_") {
  if (!data.startsWith(prefix)) return null;
  const payload = data.slice(prefix.length);
  const pageMatch = payload.match(/^(.*)_p(\d+)$/);
  const rawArchiveId = pageMatch ? pageMatch[1] : payload;
  const branchMatch = rawArchiveId.match(/^(.*)_ct_(free|paid)$/);
  return {
    archiveId: branchMatch ? branchMatch[1] : rawArchiveId,
    ...(branchMatch ? { groupContentType: branchMatch[2] as TelegramGroupContentType } : {}),
    page: pageMatch ? Math.max(0, Number(pageMatch[2] || 0)) : 0,
  };
}

function normalizeTelegramGroupContentType(value: unknown): TelegramGroupContentType | undefined {
  return value === "paid" ? "paid" : value === "free" ? "free" : undefined;
}

function contentBranchToTelegramGroupContentType(branch?: GeneratePostContentBranch): TelegramGroupContentType | undefined {
  return branch === "r18" ? "paid" : branch === "nonr18" ? "free" : undefined;
}

function telegramGroupContentTypeToContentBranch(groupContentType?: TelegramGroupContentType): GeneratePostContentBranch | undefined {
  return groupContentType === "paid" ? "r18" : groupContentType === "free" ? "nonr18" : undefined;
}

function belongsToTelegramGroupContentType(item: { telegramGroupContentType?: "free" | "paid" } | null | undefined, groupContentType?: TelegramGroupContentType) {
  if (!groupContentType) return true;
  const itemType = normalizeTelegramGroupContentType(item?.telegramGroupContentType);
  if (groupContentType === "paid") return itemType === "paid";
  return itemType !== "paid";
}

function filterByTelegramGroupContentType<T extends { telegramGroupContentType?: "free" | "paid" }>(items: T[] = [], groupContentType?: TelegramGroupContentType): T[] {
  return groupContentType ? items.filter((item) => belongsToTelegramGroupContentType(item, groupContentType)) : items;
}

function countByTelegramGroupContentType<T extends { telegramGroupContentType?: "free" | "paid" }>(items: T[] = []) {
  return items.reduce((acc: Record<TelegramGroupContentType, number>, item) => {
    const type: TelegramGroupContentType = item.telegramGroupContentType === "paid" ? "paid" : "free";
    acc[type] += 1;
    return acc;
  }, { free: 0, paid: 0 });
}

export function parseStoredPostsCallback(data: string) {
  if (!data.startsWith("posts_")) return null;
  const payload = data.slice("posts_".length);
  const pageMatch = payload.match(/^(.*)_p(\d+)$/);
  const rawArchiveId = pageMatch ? pageMatch[1] : payload;
  const branchMatch = rawArchiveId.match(/^(.*)_ct_(free|paid)$/);
  return {
    archiveId: branchMatch ? branchMatch[1] : rawArchiveId,
    ...(branchMatch ? { groupContentType: branchMatch[2] as TelegramGroupContentType } : {}),
    page: pageMatch ? Math.max(0, Number(pageMatch[2] || 0)) : 0,
  };
}

function parseFavoritePostsCallback(data: string) {
  if (!data.startsWith("favs_")) return null;
  const payload = data.slice("favs_".length);
  const pageMatch = payload.match(/^(.*)_p(\d+)$/);
  return {
    archiveId: pageMatch ? pageMatch[1] : payload,
    page: pageMatch ? Math.max(0, Number(pageMatch[2] || 0)) : 0,
  };
}

function buildStoredPostPreviewHtml(
  content: string,
  linkPresentation: { url: string; text: string } | null,
  maxChars = 120,
) {
  const raw = String(content || "");
  const linkUrl = String(linkPresentation?.url || "").trim();
  if (!linkUrl || !raw.includes(linkUrl)) {
    return escapeHtmlText(raw.slice(0, maxChars) + (raw.length > maxChars ? "..." : ""));
  }

  const moved = moveLinkPresentationToEnd(raw, linkPresentation);
  const escaped = linkUrl.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const body = moved
    .replace(new RegExp(escaped, "g"), "")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  const bodyPreview = body.slice(0, maxChars) + (body.length > maxChars ? "..." : "");
  const preview = `${bodyPreview ? `${bodyPreview}\n` : ""}${linkUrl}`.trim();
  return formatPostContentForTelegramHtml(preview, linkPresentation);
}

type StoredPostListItem = {
  id: string;
  content: string;
  telegramGroupContentType?: "free" | "paid";
  imageUrl?: string;
  mediaUrl?: string;
  mediaItems?: PersonaArchive["posts"][number]["mediaItems"];
  sourceMeta?: PersonaArchive["posts"][number]["sourceMeta"];
  imageHistory?: Array<{ imageUrl?: string | null }>;
};

function getStoredPostMediaUrlForList(post: StoredPostListItem) {
  return getStoredPostPrimaryMediaUrl(post);
}

function getStoredPostPrimaryMediaUrl(post: Pick<PersonaArchive["posts"][number], "imageUrl" | "mediaUrl" | "mediaItems" | "sourceMeta" | "imageHistory">): string {
  return String(getStoredPostMediaItems(post)[0]?.url || "").trim();
}

function resolveArchivePostCollection(archive: PersonaArchive, source?: "posts" | "favorites"): PersonaArchive["posts"] {
  return source === "favorites" ? archive.favoritePosts || [] : archive.posts || [];
}

function findArchivePostBySource(archive: PersonaArchive, postId: string, source?: "posts" | "favorites") {
  return resolveArchivePostCollection(archive, source).find((post) => post.id === postId) || null;
}

function clonePostForFavorites(post: PersonaArchive["posts"][number], favoriteCount: number): PersonaArchive["posts"][number] {
  const now = new Date().toISOString();
  const cloned = JSON.parse(JSON.stringify(post)) as PersonaArchive["posts"][number];
  return {
    ...cloned,
    id: crypto.randomUUID(),
    title: cloned.title || `收藏推文 #${favoriteCount + 1}`,
    orderIndex: favoriteCount,
    createdAt: now,
    updatedAt: now,
    publishedAt: undefined,
    publishedMemory: undefined,
    sourceMeta: {
      ...(cloned.sourceMeta || {}),
      favoriteSourcePostId: post.id,
      favoriteAddedAt: now,
    } as any,
  };
}

function isArchivePostFavorited(archive: PersonaArchive, post: PersonaArchive["posts"][number] | null | undefined): boolean {
  if (!post) return false;
  return (archive.favoritePosts || []).some((favorite) => {
    const sourcePostId = String((favorite.sourceMeta as any)?.favoriteSourcePostId || "").trim();
    return favorite.id === post.id || sourcePostId === post.id;
  });
}

async function addFavoritePostClone(archiveId: string, postId: string, source?: "posts" | "favorites") {
  const archive = await loadPersonaArchive(archiveId).catch(() => null);
  const post = archive ? findArchivePostBySource(archive, postId, source) : null;
  if (!archive || !post) return null;
  const favoritePosts = archive.favoritePosts || [];
  if (source !== "favorites" && isArchivePostFavorited(archive, post)) return archive;
  return savePersonaArchive({
    ...archive,
    favoritePosts: [...favoritePosts, clonePostForFavorites(post, favoritePosts.length)],
  });
}

async function updateFavoritePostDraft(
  archiveId: string,
  postId: string,
  updater: (post: PersonaArchive["posts"][number]) => PersonaArchive["posts"][number],
) {
  const archive = await loadPersonaArchive(archiveId).catch(() => null);
  const favoritePosts = archive?.favoritePosts || [];
  const current = favoritePosts.find((post) => post.id === postId);
  if (!archive || !current) return null;
  const updatedPost = updater(current);
  await savePersonaArchive({
    ...archive,
    favoritePosts: favoritePosts.map((post) => post.id === postId ? updatedPost : post),
  });
  return updatedPost;
}

async function deleteFavoritePost(archiveId: string, postId: string) {
  const archive = await loadPersonaArchive(archiveId).catch(() => null);
  if (!archive) return null;
  return savePersonaArchive({
    ...archive,
    favoritePosts: (archive.favoritePosts || []).filter((post) => post.id !== postId),
  });
}

function getStoredPostTypeLabelForList(post: StoredPostListItem) {
  const mediaItems = getStoredPostMediaItems(post);
  if (!mediaItems.length) return "純文字";
  let hasImage = false;
  let hasVideo = false;
  for (const item of mediaItems) {
    const kind = item.type && item.type !== "unknown" ? item.type : inferStoredPostMediaKind(item.url);
    if (kind === "video") hasVideo = true;
    else if (kind === "image") hasImage = true;
  }
  if (hasImage && hasVideo) return "圖片+視頻";
  if (hasVideo) return "視頻";
  if (hasImage) return "圖片";
  return "媒體";
}

function buildStoredPostSourceMetricLine(post: StoredPostListItem): string {
  const sourceMeta = post.sourceMeta;
  if (sourceMeta?.source !== "sentiment_hot_import") return "";
  return `数据: ${escapeHtmlText(formatSentimentMetricLine({
    hotScore: sourceMeta.hotScore,
    metrics: sourceMeta.metrics,
    engagement: sourceMeta.engagement,
  }))}`;
}

export function buildStoredPostsListView(
  archiveId: string,
  posts: StoredPostListItem[],
  page = 0,
  pageSize = STORED_POSTS_PAGE_SIZE,
  linkPresentation: { url: string; text: string } | null = null,
  groupContentType?: TelegramGroupContentType,
  favoriteCount?: number,
) {
  const scopedPosts = filterByTelegramGroupContentType(posts, groupContentType);
  const totalPages = Math.max(1, Math.ceil(scopedPosts.length / pageSize));
  const safePage = Math.min(Math.max(0, page), totalPages - 1);
  const start = safePage * pageSize;
  const visiblePosts = scopedPosts.slice(start, start + pageSize);
  const lines = visiblePosts.map((post, idx) => {
    const displayIndex = start + idx + 1;
    const typeLabel = getStoredPostTypeLabelForList(post);
    const preview = buildStoredPostPreviewHtml(post.content, linkPresentation);
    const metricLine = buildStoredPostSourceMetricLine(post);
    return `<b>【${displayIndex}】</b> <b>类型: ${escapeHtmlText(typeLabel)}</b>${metricLine ? `\n${metricLine}` : ""}\n${preview}`;
  });
  const keyboard = visiblePosts.flatMap((post, idx) => {
    const postIndex = start + idx;
    const displayIndex = start + idx + 1;
    const typeLabel = getStoredPostTypeLabelForList(post);
    return [
      [
        { text: `\uD83D\uDC41 \u67E5\u770B\u7B2C${displayIndex}\u7BC7\uFF08${typeLabel}\uFF09`, callback_data: `vp_${postIndex}` },
      ],
    ];
  });
  keyboard.push(...buildListPaginationRows({
    page: safePage,
    totalPages,
    callbackForPage: (targetPage) => buildStoredPostsPageCallback(archiveId, targetPage, groupContentType),
  }));
  if (typeof favoriteCount === "number") {
    keyboard.push([{ text: `⭐ 收藏推文（${Math.max(0, Math.floor(favoriteCount))}）`, callback_data: buildFavoritePostsPageCallback(archiveId, 0) }]);
  }
  const branchSuffix = groupContentType ? `_ct_${groupContentType}` : "";
  keyboard.push([
    { text: "\uD83D\uDE80 \u767C\u5E03\u63A8\u6587", callback_data: `bulkpub_${archiveId}${branchSuffix}_p${safePage}` },
    { text: "\uD83D\uDDD1 \u522A\u9664\u63A8\u6587", callback_data: `bulkdel_${archiveId}${branchSuffix}_p${safePage}` },
  ]);
  keyboard.push([{ text: "\u25C0\uFE0F \u8FD4\u56DE", callback_data: groupContentType ? `posts_branch_${archiveId}` : `pd_${archiveId}` }]);
  const branchTitle = groupContentType === "paid" ? "付費內容" : groupContentType === "free" ? "免費內容" : "";
  return {
    page: safePage,
    pageSize,
    totalPages,
    start,
    visiblePosts,
    visiblePostIds: visiblePosts.map((post) => post.id),
    postIds: scopedPosts.map((post) => post.id),
    text: `<b>\uD83D\uDCDD \u5F85\u767C\u4F48\u63A8\u6587\u5217\u8868</b>${branchTitle ? ` - ${branchTitle}` : ""}\uFF08\u5171 ${scopedPosts.length} \u7BC7\uFF0C\u7B2C ${safePage + 1}/${totalPages} \u9801\uFF09\n\n${lines.join("\n\n")}`,
    keyboard,
  };
}


function parseBulkStoredPostsCallback(data: string, prefix: "bulkpub_" | "bulkdel_") {
  if (!data.startsWith(prefix)) return null;
  const payload = data.slice(prefix.length);
  const pageMatch = payload.match(/^(.*)_p(\d+)$/);
  const rawArchiveId = pageMatch ? pageMatch[1] : payload;
  const branchMatch = rawArchiveId.match(/^(.*)_ct_(free|paid)$/);
  return {
    archiveId: branchMatch ? branchMatch[1] : rawArchiveId,
    ...(branchMatch ? { groupContentType: branchMatch[2] as TelegramGroupContentType } : {}),
    page: pageMatch ? Math.max(0, Number(pageMatch[2] || 0)) : 0,
  };
}

function buildBulkStoredPostsSelectView(args: {
  archiveId: string;
  posts: Array<{ id: string; content: string; telegramGroupContentType?: "free" | "paid" }>;
  mode: "publish" | "delete";
  selectedPostIds: string[];
  page?: number;
  pageSize?: number;
  groupContentType?: TelegramGroupContentType;
}) {
  const pageSize = args.pageSize || STORED_POSTS_PAGE_SIZE;
  const scopedPosts = filterByTelegramGroupContentType(args.posts, args.groupContentType);
  const totalPages = Math.max(1, Math.ceil(scopedPosts.length / pageSize));
  const safePage = Math.min(Math.max(0, args.page || 0), totalPages - 1);
  const start = safePage * pageSize;
  const visiblePosts = scopedPosts.slice(start, start + pageSize);
  const selected = new Set(args.selectedPostIds);
  const actionText = args.mode === "publish" ? "发布" : "删除";
  const lines = visiblePosts.map((post, idx) => {
    const displayIndex = start + idx + 1;
    const marker = selected.has(post.id) ? "☑" : "☐";
    return `${marker}【${displayIndex}】${post.content.slice(0, 100)}${post.content.length > 100 ? "..." : ""}`;
  });
  const keyboard = visiblePosts.map((post, idx) => {
    const postIndex = start + idx;
    const displayIndex = start + idx + 1;
    const marker = selected.has(post.id) ? "☑️" : "☐";
    return [{ text: `${marker} 第${displayIndex}篇`, callback_data: `btog_${postIndex}` }];
  });
  if (visiblePosts.length) {
    keyboard.push([
      { text: "☑️ 全选本页", callback_data: "bsel_page" },
      { text: "⬜ 清空本页", callback_data: "bclear_page" },
    ]);
  }
  keyboard.push(...buildListPaginationRows({
    page: safePage,
    totalPages,
    callbackForPage: (targetPage) => `bpage_${targetPage}`,
  }));
  keyboard.push([{ text: args.mode === "publish" ? `✅ 确认发布选择（已选${selected.size}篇）` : `✅ 确认${actionText}（已选${selected.size}篇）`, callback_data: "bconfirm" }]);
  keyboard.push([{ text: "◀️ 返回推文列表", callback_data: buildStoredPostsPageCallback(args.archiveId, safePage, args.groupContentType) }]);
  return {
    page: safePage,
    text: args.mode === "publish"
      ? `请选择要发布的推文：\n已選：${selected.size} 篇\n下一步选择平台；确认页可选择绑定设备发布或多设备发布。\n\n${lines.join("\n\n")}`
      : `请选择要${actionText}的推文：\n已選：${selected.size} 篇\n\n${lines.join("\n\n")}`,
    keyboard,
  };
}

function resolveTelegramGroupContentTypeForPost(
  post?: { telegramGroupContentType?: "free" | "paid" } | null,
  fallbackGroupContentType?: TelegramGroupContentType,
): TelegramGroupContentType | undefined {
  if (post?.telegramGroupContentType === "paid") return "paid";
  if (post?.telegramGroupContentType === "free") return "free";
  return fallbackGroupContentType;
}

function resolveTelegramTargetGroupNameForPost(
  archive: {
    boundTelegramFreeGroupId?: string;
    boundTelegramPaidGroupId?: string;
    boundTelegramFreeGroupName?: string;
    boundTelegramPaidGroupName?: string;
  } | null | undefined,
  post?: { telegramGroupContentType?: "free" | "paid" } | null,
  fallbackGroupContentType?: TelegramGroupContentType,
) {
  const groupType: TelegramGroupContentType = resolveTelegramGroupContentTypeForPost(post, fallbackGroupContentType) || "free";
  const name = groupType === "paid" ? archive?.boundTelegramPaidGroupName : archive?.boundTelegramFreeGroupName;
  return normalizeTelegramSingleLine(name || "");
}

function buildTelegramPublishPreviewTargetLine(
  platform: TelegramPublishPlatform | undefined,
  archive: {
    boundTelegramFreeGroupId?: string;
    boundTelegramPaidGroupId?: string;
    boundTelegramFreeGroupName?: string;
    boundTelegramPaidGroupName?: string;
  } | null | undefined,
  post?: { telegramGroupContentType?: "free" | "paid" } | null,
  fallbackGroupContentType?: TelegramGroupContentType,
) {
  if (platform !== "telegram") return "";
  const groupType = resolveTelegramGroupContentTypeForPost(post, fallbackGroupContentType) || "free";
  const groupName = resolveTelegramTargetGroupNameForPost(archive, post, groupType);
  return `\n\u76EE\u6A19\u7FA4\uFF1A${groupName || "\u672A\u8A2D\u5B9A"}`;
}

function resolveTelegramTargetForGroupContent(
  archive: {
    boundTelegramFreeGroupId?: string;
    boundTelegramPaidGroupId?: string;
    boundTelegramFreeGroupName?: string;
    boundTelegramPaidGroupName?: string;
  } | null | undefined,
  groupContentType?: TelegramGroupContentType,
) {
  const resolvedType: TelegramGroupContentType = groupContentType === "paid" ? "paid" : "free";
  const chatId = normalizeTelegramSingleLine(
    resolvedType === "paid" ? archive?.boundTelegramPaidGroupId || "" : archive?.boundTelegramFreeGroupId || "",
  );
  const groupName = normalizeTelegramSingleLine(
    resolvedType === "paid" ? archive?.boundTelegramPaidGroupName || "" : archive?.boundTelegramFreeGroupName || "",
  ) || (chatId ? resolveKnownTelegramGroupName(chatId, resolvedType) : "");
  return { groupContentType: resolvedType, chatId, groupName };
}

function uniquePadCodes(codes: string[]): string[] {
  return Array.from(new Set(codes.map((code) => String(code || "").trim()).filter(Boolean)));
}

export function buildPublishPadSelectionRows(args: {
  pads: Array<{ padCode: string; padName?: string }>;
  selectedPadCodes: string[];
  page?: number;
  pageSize?: number;
  confirmCallback?: string;
  backCallback?: string;
}) {
  const selected = new Set(uniquePadCodes(args.selectedPadCodes));
  const pageSize = args.pageSize || 10;
  const totalPages = Math.max(1, Math.ceil(args.pads.length / pageSize));
  const safePage = Math.min(Math.max(0, args.page || 0), totalPages - 1);
  const start = safePage * pageSize;
  const visiblePads = args.pads.slice(start, start + pageSize);
  const rows = visiblePads.map((pad, index) => {
    const checked = selected.has(pad.padCode);
    return [{
      text: `${checked ? "✅ " : "☐ "}${pad.padName || pad.padCode}`,
      callback_data: `pubpad_toggle_${index}`,
    }];
  });
  if (visiblePads.length) {
    rows.push([
      { text: "☑️ 全选本页", callback_data: "pubpad_select_page" },
      { text: "⬜ 清空本页", callback_data: "pubpad_clear_page" },
    ]);
  }
  if (args.pads.length > pageSize) {
    rows.push([
      { text: "☑️ 全选全部", callback_data: "pubpad_select_all" },
      { text: "⬜ 清空全部", callback_data: "pubpad_clear_all" },
    ]);
  }
  rows.push(...buildListPaginationRows({
    page: safePage,
    totalPages,
    callbackForPage: (targetPage) => `pubpad_page_${targetPage}`,
  }));
  rows.push([{ text: `✅ 确认发布到 ${selected.size || 0} 台设备`, callback_data: args.confirmCallback || "pubpad_confirm" }]);
  rows.push([{ text: "◀️ 返回", callback_data: args.backCallback || "pubpad_back" }]);
  return rows;
}
