function normalizePersonaHotMetricsUsername(value?: string | null) {
  return String(value || "").replace(/^@+/, "").trim().toLowerCase();
}

function buildPersonaHotMetricsKey(platform: "threads", username: string) {
  const normalized = normalizePersonaHotMetricsUsername(username);
  return `${platform}:${normalized || "unbound"}`;
}

function resolveThreadsHotAuthBinding() {
  const status = getSentimentBrowserAuthProfileBinding("threads");
  const ok = (status.health === "healthy" || status.health === "watch") && status.hasRequiredSessionCookie !== false;
  return {
    ok,
    profileKey: status.profileKey || "threads",
    status,
    message: ok
      ? "Threads 授權有效"
      : "Threads 授權未完成或已失效，請先在後台瀏覽器登入 Threads 並同步有效 sessionid。",
  };
}

async function resolveThreadsHotAuthBindingLive() {
  const status = await getLiveSentimentBrowserAuthProfileBinding("threads", { maxAgeMs: 60_000 }).catch(() => getSentimentBrowserAuthProfileBinding("threads"));
  const ok = (status.health === "healthy" || status.health === "watch") && status.hasRequiredSessionCookie !== false;
  return {
    ok,
    profileKey: status.profileKey || "threads",
    status,
    message: ok
      ? "Threads authorization is live."
      : status.message || "Threads authorization is missing or expired. Re-login in the authorization helper and sync sessionid.",
  };
}

function resolvePersonaThreadsHotMetrics(archive: PersonaArchive, legacyPadCode?: string) {
  const hotMetrics = (archive.setup as any)?.hotMetrics || {};
  const username = normalizePersonaHotMetricsUsername((archive.setup as any)?.accountManagement?.threads?.handle);
  if (username) {
    const direct = hotMetrics[buildPersonaHotMetricsKey("threads", username)];
    if (direct) return direct;
    const matched = Object.values(hotMetrics).find((item: any) =>
      String(item?.platform || "threads").toLowerCase() === "threads" &&
      normalizePersonaHotMetricsUsername(item?.username) === username);
    if (matched) return matched;
  }
  return undefined;
}

function formatPersonaHotMetricsLine(archive: PersonaArchive, legacyPadCode?: string) {
  const metrics: any = resolvePersonaThreadsHotMetrics(archive, legacyPadCode);
  if (!metrics) return "熱點數據：Threads：未刷新";
  const parts = [
    metrics.username ? `帳號 @${metrics.username}` : "",
    ...buildPersonaHotMetricParts(metrics, ["followers", "following", "recentViews", "posts", "likes", "comments", "reposts", "shares", "views"]),
  ].filter(Boolean);
  const refreshedAt = formatPersonaHotMetricsTimestamp(metrics.complete === true ? metrics.refreshedAt : (metrics.lightRefreshedAt || metrics.refreshedAt));
  const suffix = refreshedAt ? `（${refreshedAt}）` : "";
  if (parts.length) return `熱點數據：Threads：${parts.join("；")}${suffix}`;
  return `熱點數據：Threads：${metrics.error || "未識別到可用熱度資料"}${suffix}`;
}

function getPersonaAccountManagement(archive: PersonaArchive | null | undefined) {
  return archive?.setup?.accountManagement || {};
}

function maskAccountSecret(value?: string | null) {
  const raw = String(value || "").trim();
  if (!raw) return "未設定";
  if (raw.length <= 4) return "•".repeat(raw.length);
  return `${raw.slice(0, 2)}•••${raw.slice(-2)}`;
}

function normalizeAccountIdentityForCompare(value?: string | null): string {
  return String(value || "")
    .trim()
    .replace(/^@+/, "")
    .toLowerCase();
}

function buildComparableAccountIdentities(value?: string | null): string[] {
  const normalized = normalizeAccountIdentityForCompare(value);
  if (!normalized) return [];
  const values = new Set<string>([normalized]);
  if (normalized.includes("@")) {
    const localPart = normalized.split("@")[0]?.trim();
    if (localPart) values.add(localPart);
  }
  return [...values].filter(Boolean);
}

function formatThreadsDetectedAccount(result: { username?: string; email?: string }): string {
  if (result.username) return `@${normalizeAccountIdentityForCompare(result.username)}`;
  if (result.email) return normalizeAccountIdentityForCompare(result.email);
  return "";
}

function threadsQueryMatchesSavedAccount(result: { username?: string; email?: string }, expected?: string | null): boolean {
  const expectedIdentities = buildComparableAccountIdentities(expected);
  if (expectedIdentities.length === 0) return Boolean(result.username || result.email);
  const candidates = new Set<string>([
    ...buildComparableAccountIdentities(result.username),
    ...buildComparableAccountIdentities(result.email),
  ]);
  if (candidates.size === 0) return false;
  return expectedIdentities.some((expectedIdentity) =>
    [...candidates].some((candidate) =>
      candidate === expectedIdentity ||
      candidate.includes(expectedIdentity) ||
      expectedIdentity.includes(candidate),
    ),
  );
}

