function normalizeThreadsOwnPostReplyHistoryUrl(raw: unknown): string {
  return String(raw || "")
    .trim()
    .replace(/^https:\/\/www\.threads\.com\//i, "https://www.threads.net/")
    .replace(/[?#].*$/, "")
    .replace(/[)\].,，。]+$/g, "");
}

function parseThreadsOwnPostReplyMinViewsInput(text: string): number | null {
  const normalized = String(text || "").trim().replace(/,/g, "");
  const match = normalized.match(/(\d+(?:\.\d+)?)/);
  if (!match) return null;
  const base = Number(match[1]);
  if (!Number.isFinite(base) || base < 0) return null;
  const multiplier = /萬|万/.test(normalized)
    ? 10_000
    : /k/i.test(normalized)
      ? 1_000
      : 1;
  return Math.floor(base * multiplier);
}

function extractThreadsOwnPostViewCount(meta?: PersonaArchive["posts"][number]["sourceMeta"]): number | undefined {
  if (!meta) return undefined;
  const engagement = (meta as any).engagement || {};
  return numberFromMetric(engagement.viewCount ?? engagement.view_count)
    ?? pickMetricNumber((meta as any).metrics, ["view_count", "views", "play_count", "plays", "impression_count", "seenCount"]);
}

function collectPublishedThreadsOwnPostReplyTargets(archive: PersonaArchive): ThreadsOwnPostReplyTarget[] {
  const seen = new Set<string>();
  const targets: ThreadsOwnPostReplyTarget[] = [];
  const add = (url: unknown, label: string, expectedText?: string, meta?: PersonaArchive["posts"][number]["sourceMeta"], publishedAt?: string) => {
    const normalized = normalizeThreadsOwnPostReplyHistoryUrl(url);
    if (!/^https:\/\/www\.threads\.net\/@[^/\s]+\/post\/[^?\s#)]+/i.test(normalized)) return;
    if (seen.has(normalized)) return;
    seen.add(normalized);
    targets.push({
      url: normalized,
      label,
      expectedText,
      viewCount: extractThreadsOwnPostViewCount(meta),
      publishedAt,
    });
  };
  for (const record of archive.publishHistory || []) {
    if (String(record.platform || "").toLowerCase() !== "threads") continue;
    const expectedText = record.content || record.title || "";
    const aggregateMeta = aggregatePublishedTargets(record);
    add(isPublishHistoryOriginalSourceUrl(record, record.publishedUrl) ? "" : record.publishedUrl, record.title || record.id || "published", expectedText, aggregateMeta, record.publishedAt);
    const meta = getPublishHistoryValidPublishedMeta(record, record.publishedMeta);
    add(isPublishHistoryOriginalSourceUrl(record, meta?.sourceUrl) ? "" : meta?.sourceUrl, record.title || record.id || "published", expectedText, meta, record.publishedAt);
    for (const target of Array.isArray(record.publishedTargets) ? record.publishedTargets : []) {
      add(isPublishHistoryOriginalSourceUrl(record, target?.publishedUrl) ? "" : target?.publishedUrl, target?.padName || record.title || record.id || "published", expectedText, getPublishHistoryValidPublishedMeta(record, target?.publishedMeta), record.publishedAt);
      const targetMeta = getPublishHistoryValidPublishedMeta(record, target?.publishedMeta);
      add(isPublishHistoryOriginalSourceUrl(record, targetMeta?.sourceUrl) ? "" : targetMeta?.sourceUrl, target?.padName || record.title || record.id || "published", expectedText, targetMeta, record.publishedAt);
    }
  }
  const knownTargets = (archive.setup as any)?.threadsOwnPostAutoReply?.knownPostTargets;
  if (Array.isArray(knownTargets)) {
    for (const item of knownTargets) {
      add(
        item?.url,
        item?.label || "known-own-post",
        item?.expectedText || item?.label || "",
        typeof item?.viewCount === "number" ? { engagement: { viewCount: item.viewCount } } as any : undefined,
        item?.publishedAt,
      );
    }
  }
  return targets;
}

async function resolvePublishedThreadsOwnPostReplyTargets(archive: PersonaArchive): Promise<{
  archive: PersonaArchive;
  targets: ThreadsOwnPostReplyTarget[];
  recovered: number;
}> {
  const initialTargets = collectPublishedThreadsOwnPostReplyTargets(archive);
  if (initialTargets.length) return { archive, targets: initialTargets, recovered: 0 };

  const publishHistory = Array.isArray(archive.publishHistory) ? archive.publishHistory : [];
  const candidateIndexes = publishHistory
    .map((record, index) => ({ record, index }))
    .filter(({ record }) => (
      String(record.platform || "").toLowerCase() === "threads"
      && !hasPublishHistorySourceUrl(record)
      && hasPublishHistoryPadLookup(record)
      && String(record.content || "").trim()
    ))
    .slice(-15);
  if (!candidateIndexes.length) return { archive, targets: initialTargets, recovered: 0 };

  const nextHistory = [...publishHistory];
  let recovered = 0;
  for (const { record, index } of candidateIndexes) {
    const nextRecord = await attachMissingPublishHistoryThreadsUrls(record).catch((error) => {
      console.warn(`[telegram][own-post-auto-reply][url-recover-failed] record=${record.id || index} ${error instanceof Error ? error.message : String(error)}`.slice(0, 220));
      return record;
    });
    if (hasPublishHistorySourceUrl(nextRecord) && !hasPublishHistorySourceUrl(record)) recovered += 1;
    nextHistory[index] = nextRecord;
  }
  if (!recovered) return { archive, targets: initialTargets, recovered: 0 };

  const nextArchive = {
    ...archive,
    updatedAt: new Date().toISOString(),
    publishHistory: nextHistory,
  };
  await savePersonaArchive(nextArchive);
  return {
    archive: nextArchive,
    targets: collectPublishedThreadsOwnPostReplyTargets(nextArchive),
    recovered,
  };
}

function getThreadsOwnPostReplyHistory(archive: PersonaArchive): Array<{ url: string; replyText?: string; repliedAt?: string }> {
  const raw = (archive.setup as any)?.threadsOwnPostAutoReply?.repliedPosts;
  return Array.isArray(raw)
    ? raw
      .map((item) => ({
        url: normalizeThreadsOwnPostReplyHistoryUrl(item?.url),
        replyText: typeof item?.replyText === "string" ? item.replyText : undefined,
        repliedAt: typeof item?.repliedAt === "string" ? item.repliedAt : undefined,
      }))
      .filter((item) => item.url)
    : [];
}

function filterUnrepliedThreadsOwnPostTargets(
  archive: PersonaArchive,
  targets: ThreadsOwnPostReplyTarget[],
  options: { minViews?: number; maxAgeDays?: number } = {},
) {
  const replied = new Set(getThreadsOwnPostReplyHistory(archive).map((item) => item.url));
  const minViews = Math.max(0, Math.floor(options.minViews || 0));
  const maxAgeDays = Math.max(0, Math.floor(options.maxAgeDays || 0));
  const minPublishedAt = maxAgeDays > 0 ? Date.now() - maxAgeDays * 24 * 60 * 60 * 1000 : 0;
  return targets.filter((target) => {
    if (replied.has(normalizeThreadsOwnPostReplyHistoryUrl(target.url))) return false;
    if (minViews > 0 && Number(target.viewCount || 0) < minViews) return false;
    if (minPublishedAt > 0) {
      const publishedAt = Date.parse(String(target.publishedAt || ""));
      if (!Number.isFinite(publishedAt) || publishedAt < minPublishedAt) return false;
    }
    return true;
  });
}

async function refreshThreadsOwnPostReplyTargetViewCounts(
  targets: ThreadsOwnPostReplyTarget[],
  options: { enabled?: boolean; limit?: number } = {},
): Promise<ThreadsOwnPostReplyTarget[]> {
  if (!options.enabled || !targets.length) return targets;
  const limit = Math.max(1, Math.min(10, Math.floor(options.limit || 5)));
  const out = [...targets];
  for (let index = 0; index < Math.min(out.length, limit); index += 1) {
    const target = out[index];
    const url = normalizeThreadsOwnPostReplyHistoryUrl(target.url);
    if (!url) continue;
    try {
      const refreshed = await refreshSentimentSourceMetrics({
        platform: "threads",
        sourceUrl: url,
        existingEngagement: typeof target.viewCount === "number" ? { viewCount: target.viewCount } : undefined,
      });
      const viewCount = numberFromMetric(
        refreshed.engagement?.viewCount
          ?? refreshed.metrics?.view_count
          ?? refreshed.metrics?.views
          ?? refreshed.metrics?.play_count
          ?? refreshed.metrics?.plays,
      );
      if (refreshed.ok && typeof viewCount === "number") {
        out[index] = { ...target, viewCount };
        console.log(`[telegram][own-post-auto-reply][view-count] url=${url} views=${viewCount}`);
      } else {
        console.warn(`[telegram][own-post-auto-reply][view-count-missing] url=${url} message=${String(refreshed.message || "")}`.slice(0, 220));
      }
    } catch (error) {
      console.warn(`[telegram][own-post-auto-reply][view-count-failed] url=${url} ${error instanceof Error ? error.message : String(error)}`.slice(0, 220));
    }
  }
  return out;
}

