  invalidatePersonaListCache();
  await args.bot.sendMessage(args.chatId, "✅ 模板内容已更新。", {
    disable_web_page_preview: true,
    reply_markup: { inline_keyboard: [[{ text: "🔗 查看链接设置", callback_data: `linksettings_${args.archiveId}` }]] },
  });
