function buildSentimentHotEditMediaKeyboard(state: NonNullable<ReturnType<typeof pendingSentimentHotEdits.get>>) {
  const selected = new Set(state.deleteMediaIndexes || []);
  const mediaRows: Array<Array<{ text: string; callback_data: string }>> = [];
  for (let index = 0; index < state.candidate.media.length; index += 2) {
    mediaRows.push(state.candidate.media.slice(index, index + 2).map((item, offset) => {
      const mediaIndex = index + offset;
      return {
        text: `${selected.has(mediaIndex) ? "☑️" : "⬜️"} ${mediaIndex + 1}.${item.type === "video" ? "视频" : "图片"}`,
        callback_data: `shmedia_toggle_${mediaIndex}`,
      };
    }));
  }
  return [
    ...mediaRows,
    ...(state.candidate.media.length ? [[
      { text: "全选删除", callback_data: "shmedia_select_all" },
      { text: "清空选择", callback_data: "shmedia_clear" },
    ]] : []),
    [{ text: `保存并使用（删除 ${selected.size} 个媒体）`, callback_data: "shmedia_save" }],
    [{ text: "返回候选详情", callback_data: `shdet_${state.actionKey}_${state.index}` }],
  ];
}

async function renderSentimentHotEditPanel(bot: TelegramBot, chatId: number, messageId?: number) {
  const state = pendingSentimentHotEdits.get(chatId);
  if (!state) {
    await safeEditOrSend(bot, chatId, messageId, "请先从候选详情进入编辑。", {
      reply_markup: { inline_keyboard: [[{ text: "返回人设列表", callback_data: "list_personas" }]] },
    });
    return;
  }
  const selected = state.deleteMediaIndexes || [];
  const keptCount = Math.max(0, state.candidate.media.length - selected.length);
  await sendSentimentCandidateMediaPanel({
    bot,
    chatId,
    messageId,
    text: [
      "✏️ 编辑热点推文",
      "",
      `人设: ${state.archiveName}`,
      `数据: ${formatSentimentMetricLine(state.candidate)}`,
      `媒体: ${state.candidate.media.length} 个，已选删除 ${selected.length} 个，保存后保留 ${keptCount} 个`,
      "",
      "图片已按媒体编号排版；下方按钮可多选删除，红色标记表示保存时会删除。",
      "可以直接发送新文案；也可以发送图片/视频+文案来整体替换媒体。",
    ].join("\n"),
    media: state.candidate.media,
    selectedDeleteIndexes: new Set(selected),
    keyboard: buildSentimentHotEditMediaKeyboard(state),
  });
  return;
}

async function appendSentimentHotCandidatePost(args: {
  pending: PendingSentimentHotImportState;
  candidate: SentimentHotCandidate;
  index: number;
  overrideContent?: string;
  overrideMediaUrl?: string;
  overrideMediaType?: "image" | "video" | "unknown";
  overrideMediaItems?: SentimentHotCandidate["media"];
  edited?: boolean;
}) {
  const sourceCandidate = args.overrideMediaItems !== undefined ? { ...args.candidate, media: args.overrideMediaItems } : args.candidate;
  const downloadedMedia = args.overrideMediaUrl
    ? [{ type: args.overrideMediaType || "unknown", url: args.overrideMediaUrl }]
    : await downloadCandidateMedia(sourceCandidate).catch(() => sourceCandidate.media || []);
  const mediaItems = downloadedMedia
    .map((item) => ({
      url: item.localPath || item.url,
      type: item.type || "unknown",
      localPath: item.localPath,
      warning: item.warning,
    }))
    .filter((item) => item.url);
  const primaryMedia = mediaItems[0];
  const mediaUrl = primaryMedia?.url || "";
  const mediaType = args.overrideMediaType || primaryMedia?.type || (mediaUrl ? "unknown" : undefined);
  const finalContent = cleanSentimentCandidateContent(args.overrideContent || args.candidate.content);
  await appendCustomPersonaArchivePost({
    archiveId: args.pending.archiveId,
    title: `热点 #${args.index + 1}`,
    content: finalContent,
    mediaUrl: mediaUrl || undefined,
    mediaType,
    mediaItems,
    telegramGroupContentType: args.pending.contentBranch === "r18" ? "paid" : args.pending.contentBranch === "nonr18" ? "free" : undefined,
    sourceMeta: {
      source: "sentiment_hot_import",
      platform: args.candidate.platform,
      sourceUrl: args.candidate.sourceUrl,
      hotScore: args.candidate.hotScore,
      metrics: args.candidate.metrics,
      engagement: args.candidate.engagement,
      capturedAt: args.candidate.capturedAt,
      originalContent: cleanSentimentCandidateContent(args.candidate.content),
      originalMediaUrl: args.candidate.media[0]?.localPath || args.candidate.media[0]?.url,
      originalMediaUrls: args.candidate.media.map((item) => item.localPath || item.url).filter(Boolean),
      mediaItems,
      edited: args.edited === true,
      warnings: [
        ...(args.candidate.warnings || []),
        ...mediaItems.map((item) => item.warning).filter((item): item is string => Boolean(item)),
      ],
    },
  });
  return { mediaItems, mediaUrl, mediaType, finalContent };
}

async function importSentimentHotCandidate(args: {
  bot: TelegramBot;
  chatId: number;
  messageId?: number;
  actionKey: string;
  index: number;
  overrideContent?: string;
  overrideMediaUrl?: string;
  overrideMediaType?: "image" | "video" | "unknown";
  overrideMediaItems?: SentimentHotCandidate["media"];
  edited?: boolean;
}) {
  await deletePendingSentimentHotMediaPanel(args.bot, args.chatId);
  const action = sentimentHotActionKeys.get(args.actionKey);
  const pending = pendingSentimentHotImports.get(args.chatId);
  const candidate = pending?.candidates[args.index];
  if (!action || !pending || action.chatId !== args.chatId || action.archiveId !== pending.archiveId || !candidate) {
    await safeEditOrSend(args.bot, args.chatId, args.messageId, "热点候选已过期，请重新刷新抓取。", {
      reply_markup: { inline_keyboard: [[{ text: "返回新建推文", callback_data: pending ? `genpost_branch_${pending.archiveId}` : "list_personas" }]] },
    });
    return;
  }

  rememberSentimentHotSelected(pending.archiveId, candidate.id);
  const previousSelectedIndexes = getSentimentHotSelectedIndexes(pending);
  const saved = await appendSentimentHotCandidatePost({
    pending,
    candidate,
    index: args.index,
    overrideContent: args.overrideContent,
    overrideMediaUrl: args.overrideMediaUrl,
    overrideMediaType: args.overrideMediaType,
    overrideMediaItems: args.overrideMediaItems,
    edited: args.edited,
  });
  rememberSentimentHotImported(pending.archiveId, candidate.id);
  pending.candidates.splice(args.index, 1);
  pending.selectedIndexes = previousSelectedIndexes
    .filter((index) => index !== args.index)
    .map((index) => index > args.index ? index - 1 : index);
  pendingSentimentHotImports.set(args.chatId, pending);
  await safeEditOrSend(args.bot, args.chatId, args.messageId, [
    args.edited ? "✅ 已导入编辑后的热点推文" : "✅ 已导入热点推文",
    `人设: ${pending.archiveName}`,
    `来源: ${candidate.platform}`,
    `数据: ${formatSentimentMetricLine(candidate)}`,
    saved.mediaUrl ? `媒体: ${saved.mediaType || "unknown"}` : "媒体: 无",
    "已加入待发布推文，发布成功后才会写入人设记忆。",
  ].join("\n"), {
    reply_markup: {
      inline_keyboard: [
        [{ text: "查看推文列表", callback_data: `posts_${pending.archiveId}` }],
        [{ text: "继续刷新抓取", callback_data: `shrf_${args.actionKey}` }],
        [{ text: "返回人设详情", callback_data: `pd_${pending.archiveId}` }],
      ],
    },
  });
}

async function importSelectedSentimentHotCandidates(args: {
  bot: TelegramBot;
  chatId: number;
  messageId?: number;
  actionKey: string;
}) {
  await deletePendingSentimentHotMediaPanel(args.bot, args.chatId);
  const action = sentimentHotActionKeys.get(args.actionKey);
  const pending = pendingSentimentHotImports.get(args.chatId);
  if (!action || !pending || action.chatId !== args.chatId || action.archiveId !== pending.archiveId) {
    await safeEditOrSend(args.bot, args.chatId, args.messageId, "热点候选已过期，请重新刷新抓取。", {
      reply_markup: { inline_keyboard: [[{ text: "返回新建推文", callback_data: pending ? `genpost_branch_${pending.archiveId}` : "list_personas" }]] },
    });
    return;
  }
  const selectedIndexes = getSentimentHotSelectedIndexes(pending);
  if (!selectedIndexes.length) {
    await safeEditOrSend(args.bot, args.chatId, args.messageId, "请先勾选要保存的热点推文。", {
      reply_markup: { inline_keyboard: [[{ text: "返回候选列表", callback_data: `shlist_${args.actionKey}` }]] },
    });
    return;
  }

  const importedIndexes: number[] = [];
  const failedLabels: string[] = [];
  for (const index of selectedIndexes) {
    const candidate = pending.candidates[index];
    if (!candidate) continue;
    try {
      rememberSentimentHotSelected(pending.archiveId, candidate.id);
      await appendSentimentHotCandidatePost({ pending, candidate, index });
      rememberSentimentHotImported(pending.archiveId, candidate.id);
      importedIndexes.push(index);
    } catch (error: any) {
      failedLabels.push(`第 ${index + 1} 篇：${formatUserFacingError(error, "保存失败")}`);
    }
  }

  const importedSet = new Set(importedIndexes);
  pending.candidates = pending.candidates.filter((_, index) => !importedSet.has(index));
  pending.selectedIndexes = [];
  pendingSentimentHotImports.set(args.chatId, pending);

  await safeEditOrSend(args.bot, args.chatId, args.messageId, [
    importedIndexes.length ? `✅ 已批量导入 ${importedIndexes.length} 篇热点推文` : "⚠️ 本次没有成功导入热点推文",
    `人设: ${pending.archiveName}`,
    "已加入待发布推文，发布成功后才会写入人设记忆。",
    ...(failedLabels.length ? ["", "失败:", ...failedLabels.slice(0, 5)] : []),
  ].join("\n"), {
    reply_markup: {
      inline_keyboard: [
        [{ text: "查看推文列表", callback_data: `posts_${pending.archiveId}` }],
        ...(pending.candidates.length ? [[{ text: `返回候选列表（剩余 ${pending.candidates.length} 篇）`, callback_data: `shlist_${args.actionKey}` }]] : []),
        [{ text: "继续刷新抓取", callback_data: `shrf_${args.actionKey}` }],
        [{ text: "返回人设详情", callback_data: `pd_${pending.archiveId}` }],
      ],
    },
  });
}

async function saveStoredPostCustomEdit(args: {
  bot: TelegramBot;
  chatId: number;
  archiveId: string;
  postId: string;
  source?: "posts" | "favorites";
  groupContentType?: TelegramGroupContentType;
  displayIndex?: number;
  content?: string;
  mediaUrl?: string;
  mediaType?: "image" | "video" | "unknown";
  replaceMediaIndexes?: number[];
}) {
  const archive = await loadPersonaArchive(args.archiveId);
  const post = archive ? findArchivePostBySource(archive, args.postId, args.source) : null;
  if (!archive || !post) {
    await args.bot.sendMessage(args.chatId, "沒有找到這篇推文，請返回列表重新打開。");
    return;
  }
  let mediaItems = post.mediaItems;
  if (args.mediaUrl) {
    const replacement = { url: args.mediaUrl, type: args.mediaType || "unknown", localPath: args.mediaUrl };
    mediaItems = replaceStoredPostMediaSelection(getStoredPostMediaItems(post), args.replaceMediaIndexes || [], replacement);
  }
  const primaryMedia = mediaItems?.[0];
  const primaryMediaUrl = primaryMedia?.url || primaryMedia?.localPath || "";
  const patch = {
    content: args.content || post.content,
    imageUrl: args.mediaUrl ? primaryMediaUrl : post.imageUrl,
    mediaUrl: args.mediaUrl ? primaryMediaUrl : post.mediaUrl,
    mediaType: args.mediaUrl ? primaryMedia?.type || args.mediaType : post.mediaType,
    mediaItems,
    sourceMeta: {
      ...(post.sourceMeta || {}),
      edited: true,
      mediaItems: mediaItems || post.sourceMeta?.mediaItems,
      warnings: [
        ...(post.sourceMeta?.warnings || []),
        "已手動編輯推文內容",
      ],
    } as any,
    updatedAt: new Date().toISOString(),
  };
  const updated = args.source === "favorites"
    ? await updateFavoritePostDraft(args.archiveId, args.postId, (current) => ({ ...current, ...patch }))
    : await updatePersonaArchivePostDraft(args.archiveId, args.postId, {
        content: patch.content,
        imageUrl: args.mediaUrl ? primaryMediaUrl : undefined,
        mediaUrl: args.mediaUrl ? primaryMediaUrl : undefined,
        mediaType: args.mediaUrl ? primaryMedia?.type || args.mediaType : post.mediaType,
        mediaItems,
        sourceMetaPatch: {
          edited: true,
          mediaItems: mediaItems || post.sourceMeta?.mediaItems,
          warnings: patch.sourceMeta.warnings,
        },
      });
  if (!updated) {
    await args.bot.sendMessage(args.chatId, "保存推文修改失敗，請稍後重試。");
    return;
  }
  pendingPostActions.set(args.chatId, { archiveId: args.archiveId, postId: args.postId, source: args.source, groupContentType: args.groupContentType });
  const sourcePosts = resolveArchivePostCollection(archive, args.source);
  const sourceIndex = sourcePosts.findIndex((item) => item.id === updated.id);
  const displayIndex = args.displayIndex || (updated.orderIndex ?? sourceIndex) + 1;
  const mediaList = getStoredPostMediaItems(updated);
  const imageUrl = String(mediaList[0]?.url || updated.imageUrl || "").trim();
  await args.bot.sendMessage(args.chatId, `✅ 推文已保存

${buildPostDetailTextWithArchive(displayIndex, updated.content, imageUrl, archive, updated.sourceMeta)}`, {
    parse_mode: "HTML",
    ...buildPostImagePreviewOptions(imageUrl),
    reply_markup: {
      inline_keyboard: buildPostDetailActionRows({
        hasImage: mediaList.length > 0 || Boolean(imageUrl),
        publishCallback: "post_action",
        deleteCallback: "post_delete_action",
        archiveId: args.archiveId,
        postIndex: args.source === "favorites" ? undefined : archive.posts.findIndex((item) => item.id === updated.id),
        groupContentType: args.groupContentType,
        canRefreshMetrics: args.source === "favorites" ? false : canRefreshSentimentPostMetrics(updated),
        allowSentimentEditControls: args.source === "favorites" || isSentimentHotImportedPost(updated),
        favoriteCallback: args.source === "favorites" ? undefined : "post_favorite_action",
        favoriteAdded: args.source !== "favorites" && isArchivePostFavorited(archive, updated),
        backCallback: buildPostSourcePageCallback(args.archiveId, args.source, 0, args.groupContentType),
        backText: args.source === "favorites" ? "◀️ 返回收藏推文" : "◀️ 返回推文列表",
      }),
    },
  });
}

async function sendGeneratePostModePickerForArchive(bot: TelegramBot, chatId: number, archiveId: string, messageId?: number, contentBranch?: GeneratePostContentBranch) {
  const archive = await loadPersonaArchive(archiveId).catch(() => null);
  if (!archive) {
    await safeEditOrSend(bot, chatId, messageId, "人设不存在或已被删除，请重新选择。", {
      reply_markup: { inline_keyboard: [[{ text: "返回人设列表", callback_data: "list_personas" }]] },
    });
    return;
  }
  const scopedPosts = contentBranch
    ? filterByTelegramGroupContentType(archive.posts || [], contentBranchToTelegramGroupContentType(contentBranch))
    : archive.posts || [];
  const branchLine = contentBranch ? ["內容類型：" + generatePostContentBranchLabel(contentBranch)] : [];
  const backTo = contentBranch ? "genpost_branch_" + archiveId : "pd_" + archiveId;
  const backText = contentBranch ? "◀️ 返回內容類型" : "◀️ 返回人設詳情";
  const text = ["✍️ *新建推文*", "", "人設：" + archive.name, ...branchLine, "目前待發佈：" + scopedPosts.length + " 篇", "", "請選擇生成模式："].join(String.fromCharCode(10));
  await safeEditOrSend(bot, chatId, messageId, text, {
    parse_mode: "Markdown",
    reply_markup: {
      inline_keyboard: [
        [{ text: "📝 只生成推文（不配圖）", callback_data: buildGeneratePostModeCallback(archiveId, "textonly", contentBranch) }],
        [{ text: "🖼 生成推文+配圖/視頻", callback_data: buildGeneratePostModeCallback(archiveId, "withimage", contentBranch) }],
        [{ text: "🧩 自訂新建（文字/圖片/視頻）", callback_data: buildGeneratePostCustomCallback(archiveId, contentBranch) }],
        [{ text: "🔥 热点抓取", callback_data: buildGeneratePostHotCallback(archiveId, contentBranch) }],
        [{ text: backText, callback_data: backTo }],
      ],
    },
  });
}

